const org=$('Read org').all().map(r=>r.json);
const SQ=String.fromCharCode(39);const qq=s=>SQ+String(s).split(SQ).join(SQ+SQ)+SQ;
const stmts=[];
// Live Projects and Allocations (1599188575) - THE org source per the client (21 Jul):
// Commercial Accountable -> client_director, Commercial Responsible -> client_partner,
// Delivery Responsible -> delivery lead, Pod -> pod. Both pages.
const pageItems=(node,first)=>{try{const j=$(node).first().json||{};const d=j.data||{};const ip=first?((((d.boards||[])[0]||{}).items_page)||{}):(d.next_items_page||{});return Array.isArray(ip.items)?ip.items:[];}catch(e){return [];}};
const lpItems=[...pageItems('Monday live projects',true),...pageItems('LA page 2',false)];
const colByTitle=(it,frag1,frag2)=>{for(const c of (it.column_values||[])){const t=((c.column&&c.column.title)||'').toLowerCase().replace(/[^a-z]/g,'');if(t.includes(frag1)&&(!frag2||t.includes(frag2))&&c.text)return c.text;}return null;};
const firstName=v=>String(v).split(',')[0].trim();
const linkPerson=(nm,role,col,accId)=>{const n1=firstName(nm);stmts.push("WITH pe AS (INSERT INTO people (name, role, is_internal) SELECT "+qq(n1)+", "+qq(role)+", true WHERE NOT EXISTS (SELECT 1 FROM people WHERE lower(name)=lower("+qq(n1)+")) RETURNING id) UPDATE accounts SET "+col+"=COALESCE((SELECT id FROM pe),(SELECT id FROM people WHERE lower(name)=lower("+qq(n1)+") LIMIT 1)) WHERE id="+qq(accId)+";");};
let lpLinks=0;
for(const acc of org){const an=(acc.account_name||'').toLowerCase();if(!an)continue;
const it=lpItems.find(x=>{const nm=(x.name||'').toLowerCase();if(!nm)return false;if(nm.includes(an)||an.includes(nm))return true;const paren=nm.match(/\(([^)]+)\)/);return !!(paren&&an.includes(paren[1].trim()));});
if(!it)continue;lpLinks++;
const pod=colByTitle(it,'pod');
const cd=colByTitle(it,'accountable');
const cpR=colByTitle(it,'respons','commer');
const dl=colByTitle(it,'respons','delivery');
if(pod)stmts.push('UPDATE accounts SET pod='+qq(pod)+' WHERE id='+qq(acc.account_id)+';');
if(cd)linkPerson(cd,'Client Director','client_director',acc.account_id);
if(cpR)linkPerson(cpR,'Client Partner','client_partner',acc.account_id);
if(dl)stmts.push('UPDATE accounts SET delivery_lead_name='+qq(firstName(dl))+' WHERE id='+qq(acc.account_id)+';');
}
const sql=stmts.length?stmts.join(' '):'SELECT 1 AS noop;';
return [{json:{sql,statements:stmts.length,lp_links:lpLinks,la_items:lpItems.length}}];

const j=$('Monday live projects').first().json||{};const ip=((((j.data||{}).boards||[])[0]||{}).items_page)||{};const cur=ip.cursor||null;
const q=cur?('query { next_items_page(limit:500, cursor:"'+cur+'"){ cursor items { name group{ title } column_values { id text column { title } } } } }'):'query { complexity { query } }';
return [{json:{body: JSON.stringify({query:q})}}];
